package br.com.portfolio.ecommerce.outbox.infrastructure.messaging;
import br.com.portfolio.ecommerce.outbox.infrastructure.persistence.OutboxJpaRepository; import org.springframework.amqp.rabbit.core.RabbitTemplate; import org.springframework.beans.factory.annotation.Value; import org.springframework.scheduling.annotation.Scheduled; import org.springframework.stereotype.Component; import org.springframework.transaction.annotation.Transactional;
@Component public class OutboxPublisherJob { private final OutboxJpaRepository repo; private final RabbitTemplate rabbit; private final String exchange; public OutboxPublisherJob(OutboxJpaRepository repo,RabbitTemplate rabbit,@Value("${app.messaging.exchange}") String exchange){this.repo=repo;this.rabbit=rabbit;this.exchange=exchange;} @Scheduled(fixedDelay=5000) @Transactional public void publish(){ for(var e: repo.findTop50ByPublishedFalseOrderByCreatedAtAsc()){ rabbit.convertAndSend(exchange,e.eventType,e.payload); e.published=true; } } }
